```typescript
// Event types
type AccountEvent = 
  | { type: 'AccountCreated'; accountId: string; initialBalance: number }
  | { type: 'Deposited'; accountId: string; amount: number }
  | { type: 'Withdrew'; accountId: string; amount: number }
  | { type: 'Transferred'; fromAccountId: string; toAccountId: string; amount: number };

class Account {
  private accountId: string;
  private balance: number;
  private events: AccountEvent[] = [];

  constructor(accountId: string, initialBalance: number = 0) {
    this.accountId = accountId;
    this.balance = initialBalance;
    this.recordEvent({
      type: 'AccountCreated',
      accountId,
      initialBalance,
    });
  }

  private recordEvent(event: AccountEvent): void {
    this.events.push(event);
    this.applyEvent(event);
  }

  private applyEvent(event: AccountEvent): void {
    switch (event.type) {
      case 'AccountCreated':
        this.balance = event.initialBalance;
        break;
      case 'Deposited':
        this.balance += event.amount;
        break;
      case 'Withdrew':
        this.balance -= event.amount;
        break;
      case 'Transferred':
        if (event.fromAccountId === this.accountId) {
          this.balance -= event.amount;
        } else if (event.toAccountId === this.accountId) {
          this.balance += event.amount;
        }
        break;
    }
  }

  deposit(amount: number): void {
    this.recordEvent({ type: 'Deposited', accountId: this.accountId, amount });
  }

  withdraw(amount: number): void {
    this.recordEvent({ type: 'Withdrew', accountId: this.accountId, amount });
  }

  transfer(toAccountId: string, amount: number): void {
    this.recordEvent({
      type: 'Transferred',
      fromAccountId: this.accountId,
      toAccountId,
      amount,
    });
  }

  getBalance(): number {
    return this.balance;
  }

  getEvents(): AccountEvent[] {
    return [...this.events];
  }

  static fromEvents(accountId: string, events: AccountEvent[]): Account {
    const account = new Account(accountId, 0);
    account.events = [];
    account.balance = 0;
    events.forEach(event => account.applyEvent(event));
    return account;
  }
}

export { Account, AccountEvent };
```

